const q        = $input.first().json.query || {};
const search   = (q.q        || '').replace(/'/g, "''").trim();
const status   = (q.status   || '').replace(/'/g, "''").trim();
const type     = (q.type     || '').replace(/'/g, "''").trim();
const vendor   = (q.vendor   || '').replace(/'/g, "''").trim();
const fm       = (q.fm       || '').replace(/'/g, "''").trim();
const fromDate = (q.fromDate || '').replace(/'/g, "''").trim();
const toDate   = (q.toDate   || '').replace(/'/g, "''").trim();
const edcFrom  = (q.edcFrom  || '').replace(/'/g, "''").trim();
const edcTo    = (q.edcTo    || '').replace(/'/g, "''").trim();
const limit    = Math.min(parseInt(q.limit  || 50), 500);
const offset   = parseInt(q.offset || 0);

const conditions = ["c.is_deleted = 'No'"];

if (search) {
  conditions.push(`(c.complaintno LIKE '%${search}%' OR cs.storename LIKE '%${search}%' OR cs.storecode LIKE '%${search}%' OR c.productname LIKE '%${search}%' OR c.vendorname LIKE '%${search}%' OR cs.empname LIKE '%${search}%' OR ve.ticketno LIKE '%${search}%')`);
}
if (status) {
  conditions.push(`cl.status = '${status}'`);
}
if (type) {
  conditions.push(`c.typeofcomplaint = '${type}'`);
}
if (vendor) {
  conditions.push(`c.vendorname LIKE '%${vendor}%'`);
}
if (fm) {
  conditions.push(`cs.fmname LIKE '%${fm}%'`);
}
if (fromDate) {
  conditions.push(`DATE(c.created) >= '${fromDate}'`);
}
if (toDate) {
  conditions.push(`DATE(c.created) <= '${toDate}'`);
}
if (edcFrom) {
  conditions.push(`ve.closuredate >= '${edcFrom}'`);
}
if (edcTo) {
  conditions.push(`ve.closuredate <= '${edcTo}'`);
}

const where = conditions.join(' AND ');

const joins = `FROM vmm_complaints c LEFT JOIN vmm_complaintstores cs ON cs.id = c.storerefid LEFT JOIN vmm_vendorescalations ve ON ve.id = (SELECT MAX(id) FROM vmm_vendorescalations WHERE complaintid = c.id) LEFT JOIN vmm_complaintlogs cl ON cl.id = (SELECT MAX(id) FROM vmm_complaintlogs WHERE complaintid = c.id) WHERE ${where}`;

const dataSQL  = `SELECT c.id, c.complaintno, c.productname, c.producttype, c.vendorname, c.typeofcomplaint, c.tat, c.created, cs.storecode AS store_code, cs.storename AS store_name, cs.storecity AS city, cs.statename AS state, cs.fmname, cs.fmmobileno, cs.empname, cs.empmobileno, ve.id AS escalation_id, ve.closuredate AS edc, ve.escalationlevel, ve.ticketno AS vendor_ticketno, DATEDIFF(CURDATE(), c.created) AS aging, DATEDIFF(CURDATE(), ve.closuredate) AS days_overdue, cl.status AS current_status ${joins} ORDER BY c.created DESC LIMIT ${limit} OFFSET ${offset}`;

const countSQL = `SELECT COUNT(*) AS total ${joins}`;

return [{ json: { dataSQL, countSQL } }];

const rows  = $('Execute Data').all().map(i => i.json);
const ctRow = $('Execute Count').first().json;
const total = parseInt(ctRow.total ?? ctRow['COUNT(*)'] ?? rows.length);
return [{ json: { success: true, total, count: rows.length, complaints: rows } }];
